const itemList = {{node:search_node_R6noLVkp.data.data}} || [];
const poData = {{node:get_node_BCIdYPjF.data.data}};
const tablePO = poData.table_po;
let onOrderData = [];

for(const [index, item] of tablePO.entries()) {
  const itemData = itemList.find(data => item.item_id == data.id);

  if(itemData) {
    let altQty = parseFloat(item.quantity);
    let baseQty = altQty;
    let altUOM = item.quantity_uom;
    let baseUOM = itemData.based_uom;

    if(itemData.table_uom_conversion.length > 0) {
      const uomConversion = itemData.table_uom_conversion.find(
        (conv) => conv.alt_uom_id == altUOM
      );

      if(uomConversion) {
        baseQty = Math.round(altQty * uomConversion.base_qty * 1000) / 1000;
      }
    }

    onOrderData.push({
      purchase_order_number: {{table:purchase_order_no}},
      material_id: item.item_id,
      purchase_order_line: index + 1,
      scheduled_qty: baseQty,
      open_qty: baseQty,
      received_qty: 0,
      plant_id: {{table:po_plant}},
      organization_id: {{table:organization_id}},
      po_id: {{table:id}},
      po_line_id: item.id,
      parent_id: item.preq_id,
      parent_line_id: item.preq_line_id
    })
  } 
}

return { onOrderData }

