const poID = {{table:id}};
const poLineItem = {{table:table_po}};
const preqData = {{node:search_node_gHAkxTDd.data.data}};
const onOrderData = {{node:search_node_skzp6YpH.data.data}} || [];
let latestPREQData = [];

if(preqData && preqData.length > 0) {
  for(const preq of preqData) {
    // Process each preq line item
    let processedItems = preq.table_pr.map(item => {
      const poItem = poLineItem.find(po => po.preq_line_id === item.id);
      const newItem = { ...item };
      let orderQty = 0;

      if(poItem) {
        if(onOrderData.length > 0) {

          const onOrderItem = onOrderData.find(onOrder => onOrder.parent_line_id === item.id)

          orderQty = parseFloat(item.order_qty) - parseFloat(onOrderItem.scheduled_qty) + parseFloat(poItem.quantity)
        } else {
          orderQty = parseFloat(item.order_qty) + parseFloat(poItem.quantity)
        }
        newItem.order_qty = parseFloat(orderQty).toFixed(3);
        newItem.po_id = [...(item.po_id || []), poID];
        newItem.po_line_id = [...(item.po_line_id || []), poItem.id];
      }

      return newItem;
    });

    // Determine status
    let preqStatus = preq.preq_status;
    if(preq.preq_type === 'Contract' && preq.preq_status !== 'Force Completed') {
      const isCompleted = processedItems.every(item => 
        parseFloat(item.pr_line_qty) === parseFloat(item.order_qty || 0)
      );
      preqStatus = isCompleted ? 'Completed' : 'Processing';
    } else if(preq.preq_status !== 'Force Completed') {
      preqStatus = 'Completed';
    }

    processedItems = processedItems.map((preq) => {
      return {
        ...preq,
        line_status: preqStatus,
      }
    });

    // Add to results
    latestPREQData.push({
      id: preq.id,
      preq_status: preqStatus,
      table_pr: processedItems,
    });
  }
}

return { latestPREQData };

